/// <summary>
/// This is an data contract class for VolumeFromCustomers report.
/// </summary>
[DataContractAttribute,
SysOperationContractProcessing(classStr(ETGVolumeFromCustomersUIBuilder))]
internal final class ETGVolumeFromCustomersContract implements SysOperationValidatable
{
    FromDate            fromDate;
    ToDate              toDate;
    List                custAccount;
    NoYesId             deposit;
    List                invoiceId;
    List                size;

}

Method.Source:
/// <summary>
/// Gets and sets the value for data contract member FromDate
/// </summary>
/// <param name = "_fromDate">FromDate</param>
/// <returns>FromDate</returns>
[
    DataMemberAttribute('FromDate'),
    SysOperationLabelAttribute(literalStr("@ETG_New:FromDate")),
    SysOperationHelpTextAttribute(literalStr("@ETG_New:FromDate")),
    SysOperationGroupMemberAttribute('FromDate'),
    SysOperationDisplayOrderAttribute('1')
]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

