[
    DataMemberAttribute, AifCollectionType('CylinderSize', Types::String),
    SysOperationLabelAttribute(literalStr("@ETG_New:CylinderSize")),
    SysOperationHelpTextAttribute(literalStr("@ETG_New:CylinderSize")),
    SysOperationGroupMemberAttribute('CylinderSize'),
